SELECT id, user_account, student_no, real_name, age, gender, email, phone, major, advisor, grade, study_status, enroll_date, graduate_date, gpa, record_create_time FROM user
AND ( real_name LIKE CONCAT('%', #{keyword}, '%') OR student_no LIKE CONCAT('%', #{keyword}, '%') OR major LIKE CONCAT('%', #{keyword}, '%') OR advisor LIKE CONCAT('%', #{keyword}, '%') OR user_account LIKE CONCAT('%', #{keyword}, '%') )
AND major = #{major}
AND grade = #{grade}
ORDER BY id ASC

SELECT id, user_account, student_no, real_name, age, gender, email, phone, major, advisor, grade, study_status, enroll_date, graduate_date, gpa, record_create_time FROM user
